class SecureOAuthClient {
  constructor(config) {
    this.clientId = config.clientId;
    this.redirectUri = config.redirectUri;
    this.authorizationEndpoint = config.authorizationEndpoint;
    this.scopes = config.scopes || ['openid'];
    this.state = this.generateSecureState();
  }

  generateSecureState() {
    // Use crypto API for secure random state generation
    const array = new Uint32Array(10);
    crypto.getRandomValues(array);
    return Array.from(array, (num) => num.toString(16).padStart(8, '0')).join('');
  }

  async authenticate() {
    // Validate redirect URI
    try {
      new URL(this.redirectUri);
    } catch (e) {
      throw new Error('Invalid redirect URI');
    }

    const url = new URL(this.authorizationEndpoint);
    url.searchParams.append('response_type', 'token');
    url.searchParams.append('client_id', this.clientId);
    url.searchParams.append('redirect_uri', this.redirectUri);
    url.searchParams.append('scope', this.scopes.join(' '));
    url.searchParams.append('state', this.state);
    
    // Add nonce for additional security
    const nonce = this.generateSecureState();
    url.searchParams.append('nonce', nonce);
    
    window.location.href = url.toString();
  }

  handleCallback() {
    // Validate state parameter to prevent CSRF attacks
    const urlParams = new URLSearchParams(window.location.search);
    const urlState = urlParams.get('state');
    
    if (urlState && urlState !== this.state) {
      throw new Error('Invalid state parameter - possible CSRF attack');
    }

    const hash = window.location.hash.substring(1);
    const params = new URLSearchParams(hash);
    const accessToken = params.get('access_token');
    const tokenType = params.get('token_type');
    const expiresIn = params.get('expires_in');
    const error = params.get('error');
    
    // Handle OAuth errors
    if (error) {
      throw new Error(`OAuth error: ${error}`);
    }
    
    // Validate required parameters
    if (!accessToken) {
      throw new Error('No access token received');
    }

    // Clear hash from URL
    window.location.hash = '';
    
    // Store token with security considerations
    const tokenData = {
      accessToken,
      tokenType,
      expiresIn,
      timestamp: Date.now(),
      // Don't store sensitive data in localStorage
      // Use sessionStorage for tokens that should be cleared on tab close
    };
    
    // Use sessionStorage instead of localStorage for tokens
    sessionStorage.setItem('oauth_token', JSON.stringify(tokenData));
    
    return { accessToken, tokenType, expiresIn };
  }

  // Method to get stored token
  getStoredToken() {
    const tokenData = sessionStorage.getItem('oauth_token');
    if (!tokenData) return null;
    
    const parsed = JSON.parse(tokenData);
    
    // Check if token is expired
    if (parsed.expiresIn && (Date.now() - parsed.timestamp) > (parsed.expiresIn * 1000)) {
      this.clearToken();
      return null;
    }
    
    return parsed;
  }

  clearToken() {
    sessionStorage.removeItem('oauth_token');
  }
}